#!/usr/bin/env python3
"""Sync LO customizations from testing to production. Run inside ueipab17 container."""
import psycopg2, json, base64, sys

PROD_DSN = dict(host='postgres', dbname='DB_UEIPAB', user='odoo', password='odoo8069')

# Template bodies (base64-encoded from testing DB)
PAYSLIP_EMAIL_BODY  = json.loads(base64.b64decode("").decode())
ADELANTO_PREST_BODY = json.loads(base64.b64decode("").decode())

VE_TOTAL_DED_FORMULA = """# Total of all deductions (negative values)
# Use try/except for rules that may be disabled
sso = VE_SSO_DED_V2 or 0
paro = VE_PARO_DED_V2 or 0
faov = VE_FAOV_DED_V2 or 0
ari = VE_ARI_DED_V2 or 0

# INCES may be disabled - handle gracefully
try:
    inces = VE_INCES_DED_V2 or 0
except:
    inces = 0

# Other deductions (loans, advances, etc.) - may not exist for all employees
try:
    other = VE_OTHER_DED_V2 or 0
except:
    other = 0

# Loan recovery
try:
    loan = VE_LOAN_DED_V2 or 0
except:
    loan = 0

result = sso + paro + faov + ari + inces + other + loan"""

LIQUID_NET_FORMULA = """# Net Liquidation = All benefits - Deductions - Prepaid vacation/bono
# Safely get prepaid deduction (may not exist)
try:
    prepaid_deduction = LIQUID_VACATION_PREPAID_V2 or 0
except:
    prepaid_deduction = 0

# Loan recovery deduction
try:
    loan_deduction = LIQUID_LOAN_DED_V2 or 0
except:
    loan_deduction = 0

result = (
    (LIQUID_VACACIONES_V2 or 0) +
    (LIQUID_BONO_VACACIONAL_V2 or 0) +
    (LIQUID_UTILIDADES_V2 or 0) +
    (LIQUID_PRESTACIONES_V2 or 0) +
    (LIQUID_ANTIGUEDAD_V2 or 0) +
    (LIQUID_INTERESES_V2 or 0) +
    (LIQUID_FAOV_V2 or 0) +
    (LIQUID_INCES_V2 or 0) +
    prepaid_deduction +
    loan_deduction
)"""

def main():
    conn = psycopg2.connect(**PROD_DSN)
    cur = conn.cursor()
    print("=== LO Module Sync: Testing -> Production ===")

    # 1. Payslip Email template (id=37): replace broken loan block
    print("\n[1/4] Payslip Email template (id=37) - fixing loan block...")
    cur.execute("UPDATE mail_template SET body_html = %s::jsonb WHERE id = 37",
                [json.dumps(PAYSLIP_EMAIL_BODY)])
    print(f"      Updated: {cur.rowcount} row(s)")

    # 2. Adelanto Prestaciones (id=50): sync body + add missing es_VE
    print("\n[2/4] Adelanto Prestaciones template (id=50) - syncing body + es_VE...")
    cur.execute("UPDATE mail_template SET body_html = %s::jsonb WHERE id = 50",
                [json.dumps(ADELANTO_PREST_BODY)])
    print(f"      Updated: {cur.rowcount} row(s)")

    # 3. VE_TOTAL_DED_V2 (id=19): remove duplicate result line
    print("\n[3/4] VE_TOTAL_DED_V2 formula (id=19) - removing duplicate result...")
    cur.execute("UPDATE hr_salary_rule SET amount_python_compute = %s WHERE id = 19",
                [VE_TOTAL_DED_FORMULA])
    print(f"      Updated: {cur.rowcount} row(s)")

    # 4. LIQUID_NET_V2 (id=34): remove duplicate result block
    print("\n[4/4] LIQUID_NET_V2 formula (id=34) - removing duplicate result block...")
    cur.execute("UPDATE hr_salary_rule SET amount_python_compute = %s WHERE id = 34",
                [LIQUID_NET_FORMULA])
    print(f"      Updated: {cur.rowcount} row(s)")

    conn.commit()
    conn.close()
    print("\nAll changes committed. Run: docker restart ueipab17")

if __name__ == "__main__":
    main()
